"""Shared auth types."""
from dataclasses import dataclass


@dataclass
class Claims:
    user: str
    role: str


@dataclass
class Session:
    session_id: str
    user_id: str

"""Token verification module."""
from src.auth_types import Claims


def verify_token(token: str) -> Claims | None:
    if not token:
        return None
    return Claims(user="alice", role="admin")

"""Session management module."""
from src.auth_types import Session


def create_session(user_id: str) -> Session:
    return Session(session_id="sess_123", user_id=user_id)

"""Auth middleware module."""
from src.token import verify_token
from src.session import create_session


def auth_middleware(handler):
    def wrapper(request):
        token = request.get("authorization")
        claims = verify_token(token)
        if not claims:
            return {"error": "unauthorized"}, 401
        request["user"] = claims
        return handler(request)
    return wrapper
